import { browserUseAgentTool } from "../src/mastra/tools/browser-use-agent.tool";

async function runBrowserUseAgentExample() {
  console.log("Starting browser-use agent example...\n");

  // Check for required API key
  if (!process.env.OPENAI_API_KEY) {
    console.error("❌ OPENAI_API_KEY environment variable is required");
    console.log("Set it with: export OPENAI_API_KEY=your-key-here");
    return;
  }

  try {
    // Example 1: Simple search task
    console.log("1. Simple search task...");
    const simpleResult = await browserUseAgentTool.execute({
      task: "Go to google.com and search for 'TypeScript tutorials'",
      model: "openai",
      modelName: "gpt-4o",
      useVision: false,
      maxSteps: 10,
      headless: true,
    });

    console.log("Simple task result:");
    console.log("  Success:", simpleResult.success);
    console.log("  Steps:", simpleResult.steps);
    console.log("  Task completed:", simpleResult.successStatus);
    if (simpleResult.result) {
      console.log("  Result:", simpleResult.result.substring(0, 200) + "...");
    }
    if (simpleResult.error) {
      console.log("  Error:", simpleResult.error);
    }

    console.log("\n2. Research task with vision...");
    const researchResult = await browserUseAgentTool.execute({
      task: "Go to news.ycombinator.com and extract the top 3 story titles",
      model: "openai",
      modelName: "gpt-4o",
      useVision: true, // Enable vision for better understanding
      maxSteps: 15,
      headless: true,
    });

    console.log("Research task result:");
    console.log("  Success:", researchResult.success);
    console.log("  Steps:", researchResult.steps);
    console.log("  Task completed:", researchResult.successStatus);
    if (researchResult.result) {
      console.log("  Result:", researchResult.result);
    }
    if (researchResult.error) {
      console.log("  Error:", researchResult.error);
    }

    console.log("\n3. Complex multi-step task...");
    const complexResult = await browserUseAgentTool.execute({
      task: "Go to wikipedia.org, search for 'Artificial Intelligence', read the first paragraph, and summarize it",
      model: "openai",
      modelName: "gpt-4o",
      useVision: false,
      maxSteps: 20,
      headless: true,
    });

    console.log("Complex task result:");
    console.log("  Success:", complexResult.success);
    console.log("  Steps:", complexResult.steps);
    console.log("  Task completed:", complexResult.successStatus);
    if (complexResult.result) {
      console.log("  Result:", complexResult.result);
    }
    if (complexResult.error) {
      console.log("  Error:", complexResult.error);
    }

    console.log("\n✅ Browser-use agent examples completed!");

  } catch (error) {
    console.error("\n❌ Error during browser-use agent example:", error);
  }
}

// Run example
runBrowserUseAgentExample().catch(console.error);

